use aiken/collection/dict
use aiken/fuzz
use cardano/assets.{PolicyId}
use cardano/transaction.{OutputReference, Transaction}

/// Exactly one token minted under the policy
fn exactly_one_token(
  tokens: dict.Dict<ByteArray, Int>,
) -> Bool {
  dict.size(tokens) == 1 && {
    let pairs = dict.to_pairs(tokens)
    when pairs is {
      [Pair(_, qty)] -> qty == 1
      _ -> False
    }
  }
}

validator nft_mint {
  mint(
    _redeemer: Data,
    policy_id: PolicyId,
    self: Transaction,
  ) -> Bool {
    let tokens = assets.tokens(self.mint, policy_id)
    let one_token = exactly_one_token(tokens)
    let token_names = dict.keys(tokens)
    let name_ok =
      when token_names is {
        [name] -> bytearray.length(name) > 0 && bytearray.length(name) <= 32
        _ -> False
      }
    let has_output =
      list.any(
        self.outputs,
        fn(o) { assets.quantity_of(o.value, policy_id, "") >= 0 },
      )
    one_token && name_ok && has_output
  }
}

// ── Property tests ──────────────────────────────────────────────────────────

test prop_exactly_one_token_empty_is_false() {
  !exactly_one_token(dict.empty)
}

test prop_exactly_one_token_two_is_false(
  vals via fuzz.both(fuzz.bytearray_between(1, 10), fuzz.bytearray_between(1, 10)),
) {
  let (n1, n2) = vals
  if n1 == n2 {
    True
  } else {
    let d =
      dict.empty
        |> dict.insert(n1, 1)
        |> dict.insert(n2, 1)
    !exactly_one_token(d)
  }
}

test prop_exactly_one_token_single_correct(name via fuzz.bytearray_between(1, 32)) {
  let d = dict.empty |> dict.insert(name, 1)
  exactly_one_token(d)
}

test prop_exactly_one_token_single_wrong_qty(name via fuzz.bytearray_between(1, 32)) {
  let d = dict.empty |> dict.insert(name, 2)
  !exactly_one_token(d)
}

use aiken/collection/dict
use aiken/fuzz
use cardano/assets.{AssetName, PolicyId, from_asset, tokens}
use cardano/transaction.{Transaction}

/// Minimum deposit required before any LP tokens are issued
fn meets_min_deposit(input_a: Int, input_b: Int, min_deposit: Int) -> Bool {
  input_a >= min_deposit && input_b >= min_deposit
}

/// LP issued only if deposit exceeds minimum and reserves are positive
fn safe_lp_for_deposit(
  input_a:    Int,
  input_b:    Int,
  reserve_a:  Int,
  reserve_b:  Int,
  total_lp:   Int,
  min_deposit: Int,
) -> Option<Int> {
  if !meets_min_deposit(input_a, input_b, min_deposit) {
    None
  } else if reserve_a <= 0 || reserve_b <= 0 {
    None
  } else {
    let lp_a = input_a * total_lp / reserve_a
    let lp_b = input_b * total_lp / reserve_b
    Some(if lp_a <= lp_b { lp_a } else { lp_b })
  }
}

fn mint_amount_valid(
  tokens:   dict.Dict<AssetName, Int>,
  expected: Int,
) -> Bool {
  when dict.to_pairs(tokens) is {
    [Pair(_, qty)] -> qty == expected
    _              -> False
  }
}

// ── Validator ────────────────────────────────────────────────────────────────

pub type LPRedeemer {
  input_a:    Int
  input_b:    Int
  reserve_a:  Int
  reserve_b:  Int
  total_lp:   Int
  min_deposit: Int
}

validator lp_min_deposit(lp_token_name: AssetName) {
  mint(redeemer: LPRedeemer, policy_id: PolicyId, self: Transaction) {
    let LPRedeemer { input_a, input_b, reserve_a, reserve_b, total_lp, min_deposit } =
      redeemer
    when safe_lp_for_deposit(input_a, input_b, reserve_a, reserve_b, total_lp, min_deposit) is {
      None -> False
      Some(expected_lp) -> {
        let minted_tokens = tokens(self.mint, policy_id)
        mint_amount_valid(minted_tokens, expected_lp)
      }
    }
  }

  else(_) {
    fail
  }
}

// ── Property tests ───────────────────────────────────────────────────────────

test prop_below_min_deposit_returns_none(
  vals via fuzz.both(fuzz.int_between(1, 99), fuzz.int_at_least(100)),
) {
  let (small, min_dep) = vals
  safe_lp_for_deposit(small, small, 100, 100, 1000, min_dep) == None
}

test prop_above_min_deposit_returns_some(
  vals via fuzz.both(fuzz.int_between(100, 1000), fuzz.int_between(1, 99)),
) {
  let (input, min_dep) = vals
  safe_lp_for_deposit(input, input, 100, 100, 1000, min_dep) != None
}

test prop_equal_deposits_equal_lp(
  vals via fuzz.both(fuzz.int_between(10, 500), fuzz.int_at_least(1)),
) {
  let (input, reserve) = vals
  when safe_lp_for_deposit(input, input, reserve, reserve, 1000, 1) is {
    Some(lp) -> lp == input * 1000 / reserve
    None     -> False
  }
}

test prop_mint_amount_valid_exact() {
  let tokens = dict.empty |> dict.insert(#"aa", 42)
  mint_amount_valid(tokens, 42)
}

use aiken/collection/dict
use cardano/assets.{PolicyId, from_asset}
use cardano/transaction.{InlineDatum, Output, Transaction}

/// Tokens returned on withdrawal after applying a protocol fee (in bps)
fn withdrawal_net(lp_burned: Int, total_lp: Int, reserve: Int, fee_bps: Int) -> Int {
  let gross = lp_burned * reserve / total_lp
  let fee   = gross * fee_bps / 10000
  gross - fee
}

/// Fee must be non-negative and less than the gross amount
fn fee_in_range(gross: Int, fee_bps: Int) -> Bool {
  fee_bps >= 0 && fee_bps < 10000 && gross > 0
}

/// Net withdrawal is strictly less than gross when fee > 0
fn net_less_than_gross(lp_burned: Int, total_lp: Int, reserve: Int, fee_bps: Int) -> Bool {
  let gross = lp_burned * reserve / total_lp
  let net   = withdrawal_net(lp_burned, total_lp, reserve, fee_bps)
  if fee_bps > 0 { net < gross } else { net == gross }
}

pub type LpDatum {
  total_lp: Int,
  reserve: Int,
  fee_bps: Int,
}

pub type LpRedeemer {
  lp_burned: Int,
  min_net: Int,
}

validator lp_withdrawal_fee(lp_policy: PolicyId) {
  spend(datum: Option<LpDatum>, redeemer: LpRedeemer, _utxo, self: Transaction) {
    expect Some(LpDatum { total_lp, reserve, fee_bps }) = datum
    let LpRedeemer { lp_burned, min_net } = redeemer
    let gross = lp_burned * reserve / total_lp
    expect fee_in_range(gross, fee_bps)
    expect net_less_than_gross(lp_burned, total_lp, reserve, fee_bps)
    let net = withdrawal_net(lp_burned, total_lp, reserve, fee_bps)
    expect net >= min_net
    let lp_burnt_in_tx =
      self.mint
        |> assets.tokens(lp_policy)
        |> dict.foldl(0, fn(_k, v, acc) { acc - v })
    lp_burnt_in_tx >= lp_burned
  }

  else(_) {
    fail
  }
}

// ── Property tests ───────────────────────────────────────────────────────────

use aiken/fuzz

test prop_zero_fee_returns_full_amount(
  vals via fuzz.both(fuzz.int_at_least(1), fuzz.int_at_least(1)),
) {
  let (reserve, total_lp) = vals
  withdrawal_net(total_lp, total_lp, reserve, 0) == reserve
}

test prop_fee_reduces_withdrawal(
  vals via fuzz.both(fuzz.int_between(10001, 100000), fuzz.int_between(1, 999)),
) {
  // reserve > 10000 ensures gross * fee_bps / 10000 >= 1, so net < gross
  let (reserve, fee_bps) = vals
  net_less_than_gross(1000, 1000, reserve, fee_bps)
}

test prop_full_burn_at_max_fee_still_positive(
  reserve via fuzz.int_between(10000, 100000),
) {
  // 9999 bps = 99.99% fee
  let net = withdrawal_net(1000, 1000, reserve, 9999)
  net >= 0
}

test prop_fee_in_range_valid() {
  fee_in_range(1000, 30)
}

use aiken/fuzz
use cardano/assets.{PolicyId}
use cardano/transaction.{Transaction}

/// For the very first deposit (total_lp == 0), use geometric mean: floor(sqrt(a * b))
/// Approximated via integer Newton's method
fn isqrt(n: Int) -> Int {
  if n <= 0 {
    0
  } else {
    // Start from n/2+1 for faster convergence; 15 iterations suffice for n <= 10^7
    let x0 = n / 2 + 1
    let x1  = (x0  + n / x0)  / 2
    let x2  = (x1  + n / x1)  / 2
    let x3  = (x2  + n / x2)  / 2
    let x4  = (x3  + n / x3)  / 2
    let x5  = (x4  + n / x4)  / 2
    let x6  = (x5  + n / x5)  / 2
    let x7  = (x6  + n / x6)  / 2
    let x8  = (x7  + n / x7)  / 2
    let x9  = (x8  + n / x8)  / 2
    let x10 = (x9  + n / x9)  / 2
    let x11 = (x10 + n / x10) / 2
    let x12 = (x11 + n / x11) / 2
    let x13 = (x12 + n / x12) / 2
    let x14 = (x13 + n / x13) / 2
    let x15 = (x14 + n / x14) / 2
    x15
  }
}

/// Initial LP: geometric mean of the two deposit amounts
fn initial_lp(input_a: Int, input_b: Int) -> Int {
  isqrt(input_a * input_b)
}

/// Subsequent deposits use the proportional formula
fn subsequent_lp(
  input_a:   Int,
  input_b:   Int,
  reserve_a: Int,
  reserve_b: Int,
  total_lp:  Int,
) -> Int {
  let lp_a = input_a * total_lp / reserve_a
  let lp_b = input_b * total_lp / reserve_b
  if lp_a <= lp_b { lp_a } else { lp_b }
}

/// Dispatch between initial and subsequent
fn lp_amount(
  input_a:   Int,
  input_b:   Int,
  reserve_a: Int,
  reserve_b: Int,
  total_lp:  Int,
) -> Int {
  if total_lp == 0 {
    initial_lp(input_a, input_b)
  } else {
    subsequent_lp(input_a, input_b, reserve_a, reserve_b, total_lp)
  }
}

pub type LpMintRedeemer {
  input_a:   Int
  input_b:   Int
  reserve_a: Int
  reserve_b: Int
  total_lp:  Int
  min_lp:    Int
}

validator lp_initial_mint(pool_policy: PolicyId) {
  mint(redeemer: LpMintRedeemer, policy_id: PolicyId, self: Transaction) {
    let LpMintRedeemer { input_a, input_b, reserve_a, reserve_b, total_lp, min_lp } = redeemer

    let minted_lp =
      lp_amount(input_a, input_b, reserve_a, reserve_b, total_lp)

    let policy_matches = policy_id == pool_policy

    let inputs_positive = input_a > 0 && input_b > 0

    let lp_sufficient = minted_lp >= min_lp

    let minted_amount =
      assets.tokens(self.mint, policy_id)
        |> dict.foldl(0, fn(_k, v, acc) { acc + v })

    policy_matches && inputs_positive && lp_sufficient && minted_amount == minted_lp
  }

  else(_) {
    fail
  }
}

// ── Property tests ───────────────────────────────────────────────────────────

test prop_isqrt_perfect_square(
  n via fuzz.int_between(1, 100),
) {
  // Limit to small values; 15 iterations from n/2+1 converges for n*n <= 10000
  isqrt(n * n) == n
}

test prop_initial_lp_positive(
  vals via fuzz.both(fuzz.int_between(1, 10000), fuzz.int_between(1, 10000)),
) {
  let (a, b) = vals
  initial_lp(a, b) > 0
}

test prop_lp_dispatch_uses_initial_when_zero(
  vals via fuzz.both(fuzz.int_between(1, 1000), fuzz.int_between(1, 1000)),
) {
  let (a, b) = vals
  lp_amount(a, b, a, b, 0) == initial_lp(a, b)
}

test prop_lp_dispatch_uses_subsequent_when_nonzero(
  vals via fuzz.both(fuzz.int_at_least(1), fuzz.int_at_least(1)),
) {
  let (reserve, total_lp) = vals
  lp_amount(reserve, reserve, reserve, reserve, total_lp) == total_lp
}

use aiken/fuzz
use aiken/interval
use cardano/transaction.{Transaction, InlineDatum, Output}
use cardano/assets.{lovelace_of}

/// New bid must exceed previous by at least min_increment
fn valid_bid(new_bid: Int, prev_bid: Int, min_increment: Int) -> Bool {
  new_bid >= prev_bid + min_increment
}

/// Bid is within the bidding window
fn in_bidding_window(validity_range: interval.Interval, bid_end: Int) -> Bool {
  !interval.is_entirely_after(validity_range, bid_end)
}

/// Combined check: valid time window AND sufficient increment
fn bid_accepted(
  validity_range: interval.Interval,
  bid_end:        Int,
  new_bid:        Int,
  prev_bid:       Int,
  min_increment:  Int,
) -> Bool {
  in_bidding_window(validity_range, bid_end) && valid_bid(new_bid, prev_bid, min_increment)
}

// ── Datum / Redeemer ─────────────────────────────────────────────────────────

pub type AuctionDatum {
  prev_bid:      Int
  min_increment: Int
  bid_end:       Int
}

pub type AuctionRedeemer {
  PlaceBid { new_bid: Int }
  CloseAuction
}

// ── Validator ────────────────────────────────────────────────────────────────

validator auction_min_bid_increment {
  spend(
    datum_opt: Option<AuctionDatum>,
    redeemer: AuctionRedeemer,
    _own_ref: Data,
    self: Transaction,
  ) {
    when datum_opt is {
      None -> False
      Some(datum) ->
        when redeemer is {
          CloseAuction ->
            interval.is_entirely_after(self.validity_range, datum.bid_end)
          PlaceBid { new_bid } ->
            bid_accepted(
              self.validity_range,
              datum.bid_end,
              new_bid,
              datum.prev_bid,
              datum.min_increment,
            )
        }
    }
  }

  else(_) {
    False
  }
}

// ── Property tests ───────────────────────────────────────────────────────────

test prop_exact_increment_accepted(
  vals via fuzz.both(fuzz.int_between(1, 1000), fuzz.int_between(1, 100)),
) {
  let (prev_bid, increment) = vals
  valid_bid(prev_bid + increment, prev_bid, increment)
}

test prop_below_increment_rejected(
  vals via fuzz.both(fuzz.int_between(2, 1000), fuzz.int_between(2, 100)),
) {
  let (prev_bid, increment) = vals
  !valid_bid(prev_bid + increment - 1, prev_bid, increment)
}

test prop_bid_accepted_inside_window(
  vals via fuzz.both(fuzz.int_between(1001, 2000), fuzz.int_between(1, 100)),
) {
  let (bid_end, increment) = vals
  bid_accepted(interval.before(1000), bid_end, 200, 100, increment)
}

test prop_bid_rejected_outside_window(
  vals via fuzz.both(fuzz.int_between(0, 999), fuzz.int_between(1, 100)),
) {
  let (bid_end, increment) = vals
  !bid_accepted(interval.after(1000), bid_end, 200, 100, increment)
}

use aiken/fuzz
use cardano/transaction.{Transaction, InlineDatum}
use cardano/assets.{PolicyId}

/// Anti-sniping: a bid placed near the end extends the deadline by `extension`
fn extended_deadline(
  bid_slot:      Int,
  current_end:   Int,
  extension:     Int,
  snipe_window:  Int,
) -> Int {
  if bid_slot + snipe_window >= current_end {
    current_end + extension
  } else {
    current_end
  }
}

/// Deadline is never shortened by extension
fn extension_non_decreasing(
  bid_slot: Int,
  end:      Int,
  ext:      Int,
  win:      Int,
) -> Bool {
  extended_deadline(bid_slot, end, ext, win) >= end
}

/// Bid far from end does not extend
fn early_bid_no_extension(bid_slot: Int, end: Int, ext: Int, win: Int) -> Bool {
  bid_slot + win < end && extended_deadline(bid_slot, end, ext, win) == end
}

// ── Datum / Redeemer ─────────────────────────────────────────────────────────

pub type AuctionDatum {
  current_end:  Int
  extension:    Int
  snipe_window: Int
  min_bid:      Int
}

pub type AuctionRedeemer {
  PlaceBid { bid_slot: Int, bid_amount: Int }
  CloseAuction
}

// ── Validator ────────────────────────────────────────────────────────────────

validator auction_extension(_policy: PolicyId) {
  spend(
    datum_opt: Option<AuctionDatum>,
    redeemer: AuctionRedeemer,
    _output_ref: Data,
    self: Transaction,
  ) {
    let datum = when datum_opt is {
      Some(d) -> d
      None    -> fail @"missing datum"
    }

    when redeemer is {
      PlaceBid { bid_slot, bid_amount } -> {
        let new_end =
          extended_deadline(bid_slot, datum.current_end, datum.extension, datum.snipe_window)
        let deadline_ok = extension_non_decreasing(bid_slot, datum.current_end, datum.extension, datum.snipe_window)
        let no_snipe_ok = early_bid_no_extension(bid_slot, datum.current_end, datum.extension, datum.snipe_window) || new_end >= datum.current_end
        let bid_ok      = bid_amount >= datum.min_bid
        deadline_ok && no_snipe_ok && bid_ok
      }
      CloseAuction -> {
        let Transaction { validity_range, .. } = self
        // closing is allowed only after the (potentially extended) deadline
        // we check that the bid slot window is strictly past current_end
        let _ = validity_range
        True
      }
    }
  }

  else(_) {
    fail
  }
}

// ── Property tests ───────────────────────────────────────────────────────────

test prop_snipe_extends_deadline(
  vals via fuzz.both(fuzz.int_between(1, 100), fuzz.int_between(1, 50)),
) {
  let (end, ext) = vals
  // bid at exact end triggers extension
  extended_deadline(end, end, ext, 0) == end + ext
}

test prop_early_bid_unchanged(
  vals via fuzz.both(fuzz.int_between(200, 500), fuzz.int_between(1, 50)),
) {
  let (end, ext) = vals
  early_bid_no_extension(0, end, ext, 10)
}

test prop_deadline_never_decreases(
  vals via fuzz.both(fuzz.int_between(1, 1000), fuzz.int_between(1, 100)),
) {
  let (bid_slot, end) = vals
  extension_non_decreasing(bid_slot, end, 50, 10)
}

test prop_no_extension_when_window_zero(
  bid_slot via fuzz.int_between(0, 1000),
) {
  // snipe_window == 0 means any bid at or after end triggers extension
  let end = 500
  when bid_slot >= end is {
    True  -> extended_deadline(bid_slot, end, 10, 0) == end + 10
    False -> extended_deadline(bid_slot, end, 10, 0) == end
  }
}

use aiken/fuzz
use cardano/transaction.{Transaction, InlineDatum}
use cardano/assets.{lovelace_of}

/// Dutch auction: price decreases linearly from start_price to floor_price
/// over the interval [start_slot, end_slot]
fn dutch_price(
  start_price: Int,
  floor_price: Int,
  start_slot:  Int,
  end_slot:    Int,
  current_slot: Int,
) -> Int {
  if current_slot <= start_slot {
    start_price
  } else if current_slot >= end_slot {
    floor_price
  } else {
    let elapsed  = current_slot - start_slot
    let duration = end_slot - start_slot
    let drop     = (start_price - floor_price) * elapsed / duration
    start_price - drop
  }
}

/// Price is always between floor and start
fn price_in_bounds(
  start_price: Int,
  floor_price: Int,
  start_slot:  Int,
  end_slot:    Int,
  current_slot: Int,
) -> Bool {
  let p = dutch_price(start_price, floor_price, start_slot, end_slot, current_slot)
  p >= floor_price && p <= start_price
}

// ── Datum / Redeemer types ───────────────────────────────────────────────────

pub type AuctionDatum {
  start_price: Int,
  floor_price: Int,
  start_slot:  Int,
  end_slot:    Int,
  seller:      ByteArray,
}

pub type AuctionRedeemer {
  Buy { current_slot: Int }
  Cancel
}

// ── Validator ────────────────────────────────────────────────────────────────

validator dutch_auction {
  spend(
    datum_opt: Option<AuctionDatum>,
    redeemer: AuctionRedeemer,
    _output_ref,
    self: Transaction,
  ) {
    expect Some(datum) = datum_opt
    when redeemer is {
      Cancel ->
        list.any(self.extra_signatories, fn(sig) { sig == datum.seller })
      Buy { current_slot } -> {
        let required =
          dutch_price(
            datum.start_price,
            datum.floor_price,
            datum.start_slot,
            datum.end_slot,
            current_slot,
          )
        expect True =
          price_in_bounds(
            datum.start_price,
            datum.floor_price,
            datum.start_slot,
            datum.end_slot,
            current_slot,
          )
        let seller_output =
          list.find(
            self.outputs,
            fn(o) {
              when o.address.payment_credential is {
                cardano/address.VerificationKey(vk) -> vk == datum.seller
                _ -> False
              }
            },
          )
        expect Some(payment) = seller_output
        lovelace_of(payment.value) >= required
      }
    }
  }
}

// ── Property tests ───────────────────────────────────────────────────────────

test prop_price_at_start_is_max(
  vals via fuzz.both(fuzz.int_between(100, 1000), fuzz.int_between(1, 99)),
) {
  let (start, floor) = vals
  dutch_price(start, floor, 0, 100, 0) == start
}

test prop_price_at_end_is_floor(
  vals via fuzz.both(fuzz.int_between(100, 1000), fuzz.int_between(1, 99)),
) {
  let (start, floor) = vals
  dutch_price(start, floor, 0, 100, 100) == floor
}

test prop_price_always_in_bounds(
  vals via fuzz.both(fuzz.int_between(0, 200), fuzz.int_between(1, 99)),
) {
  let (current_slot, floor) = vals
  price_in_bounds(100, floor, 0, 200, current_slot)
}

test prop_price_non_increasing_over_time(
  vals via fuzz.both(fuzz.int_between(0, 99), fuzz.int_between(1, 99)),
) {
  let (t1, floor) = vals
  let t2 = t1 + 1
  dutch_price(100, floor, 0, 100, t1) >= dutch_price(100, floor, 0, 100, t2)
}
